// ops_messages.go — hand-written proto message types for ops-svc RPCs.
//
// These types would normally be generated by protoc from ops.proto.
// They are written by hand because protoc is not available in the sandbox.
// Run `make genpb` to regenerate cleanly from ops.proto once protoc is
// available in the build environment.

package pb

// ---------------------------------------------------------------------------
// RunRoomAllocation
// ---------------------------------------------------------------------------

// RunRoomAllocationRequest triggers a room allocation run for a departure.
type RunRoomAllocationRequest struct {
	DepartureId string   // UUID string
	JamaahIds   []string // list of jamaah UUID strings to allocate
}

func (x *RunRoomAllocationRequest) GetDepartureId() string {
	if x == nil {
		return ""
	}
	return x.DepartureId
}

func (x *RunRoomAllocationRequest) GetJamaahIds() []string {
	if x == nil {
		return nil
	}
	return x.JamaahIds
}

// RoomAssignmentProto represents a single room assignment.
type RoomAssignmentProto struct {
	RoomNumber string
	JamaahId   string
}

func (x *RoomAssignmentProto) GetRoomNumber() string {
	if x == nil {
		return ""
	}
	return x.RoomNumber
}

func (x *RoomAssignmentProto) GetJamaahId() string {
	if x == nil {
		return ""
	}
	return x.JamaahId
}

// RunRoomAllocationResponse contains the result of the allocation run.
type RunRoomAllocationResponse struct {
	AllocationId string
	RoomCount    int32
	Assignments  []*RoomAssignmentProto
}

func (x *RunRoomAllocationResponse) GetAllocationId() string {
	if x == nil {
		return ""
	}
	return x.AllocationId
}

func (x *RunRoomAllocationResponse) GetRoomCount() int32 {
	if x == nil {
		return 0
	}
	return x.RoomCount
}

func (x *RunRoomAllocationResponse) GetAssignments() []*RoomAssignmentProto {
	if x == nil {
		return nil
	}
	return x.Assignments
}

